ribute developments correctly. risk must begin with Low, Medium or High then a short rationale. For movers, use the LEADERSHIP/BOARD CHANGES DIGEST and include every appointment, resignation, promotion or board change; when a mover's name, previous role, new role or date is not stated, set that field to 'Not specified'. If a PREVIOUS EDITION SUMMARY is provided, make the brief week-over-week aware: populate weekOverWeek with the key changes since then and reflect momentum versus last edition in signals where relevant. Output ONLY the JSON object."},
    {"role":"user","content": {{ JSON.stringify('NEWS DIGEST for ' + ($json.date||'') + ' (' + ($json.count||0) + ' items):\n' + ($json.articles||'') + '\n\nLEADERSHIP/BOARD CHANGES DIGEST (' + ($json.moversCount||0) + ' items):\n' + ($json.moversDigest||'None retrieved.') + '\n\nPREVIOUS EDITION SUMMARY:\n' + ($json.previous||'No previous edition available.')) }} }
  ]
}

parameters.jsCode:
const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l); }).slice(0,4).join('; ') || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs. NO text, NO logos, NO faces.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

let raw = ($json && $json.markdown) || '';
let data = null;
try { data = JSON.parse(raw); } catch (e) { try { var m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
const fs = require('fs');
function fileUri(base){ var t=[['/config/branding/'+base+'.png','image/png'],['/config/branding/'+base+'.jpg','image/jpeg'],['/config/branding/'+base+'.jpeg','image/jpeg']]; for(var i=0;i<t.length;i++){ try { return 'data:'+t[i][1]+';base64,'+fs.readFileSync(t[i][0]).toString('base64'); } catch(e){} } return ''; }
const cover=fileUri('cover'), banner=fileUri('banner'), avatar=fileUri('jarvis-avatar');
let hero=''; try { var hb=$('Generate Cover (Image Provider)').first().json.data[0].b64_json; if(hb) hero='data:image/png;base64,'+hb; } catch(e){ hero=''; }
function ord(n){ var s=['th','st','nd','rd'], v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); }
function prettyDate(d){ try { var p=(d||'').split('-'); var dt=new Date(Number(p[0]),Number(p[1])-1,Number(p[2])); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); } catch(e){ return d; } }
const dateStr=prettyDate(date);
const weekOf=(data && data.weekOf) ? data.weekOf : dateStr;

function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function riskColor(r){ r=(r||'').toString().toLowerCase(); if(r.indexOf('high')===0)return '#B02525'; if(r.indexOf('med')===0)return '#B8860B'; if(r.indexOf('low')===0)return '#1E8E5A'; return '#5A6472'; }

var CSS = '*{box-sizing:border-box} '
 + 'body{margin:0;font-family:-apple-system,"Segoe UI",Arial,sans-serif;color:#11151c;font-size:14px;line-height:1.55} '
 + '.cover{height:100vh;background-image:url('+cover+');background-size:cover;background-position:center;page-break-after:always;position:relative} '
 + '.cover .date{position:absolute;top:24px;right:30px;color:#fff;font-family:Georgia,serif;font-size:23px;font-weight:700;text-shadow:0 2px 6px rgba(0,0,0,.75)} '
 + '.banner{width:100%;display:block} '
 + '.issuebar{background:#0A1A2F;color:#cfe0f0;padding:9px 40px;font-size:11px;letter-spacing:2px;text-transform:uppercase} '
 + '.issuebar .r{float:right;color:#5BB6F0} '
 + '.hero{height:280px;background-image:url('+hero+');background-size:cover;background-position:center;background-color:#0A1A2F;border-bottom:4px solid #2E9BE6} '
 + '.wrap{padding:26px 40px 10px} '
 + '.lead{font-size:16px;line-height:1.75;margin:0 0 4px} '
 + '.lead .dc{float:left;font-family:Georgia,serif;font-size:56px;line-height:44px;padding:6px 12px 0 0;color:#2E9BE6;font-weight:700} '
 + '.callout{background:#EAF4FC;border-left:4px solid #2E9BE6;padding:12px 16px;margin:18px 0;font-size:14px} '
 + 'h2.sec{font-family:Georgia,serif;font-size:21px;color:#0A1A2F;margin:34px 0 10px;padding-bottom:8px;border-bottom:2px solid #0A1A2F} '
 + 'h2.sec .kick{display:block;font-family:Arial;font-size:10.5px;letter-spacing:2px;color:#2E9BE6;text-transform:uppercase;margin-bottom:3px;font-weight:700} '
 + '.feature{border:1px solid #E2E6EC;border-radius:8px;overflow:hidden;margin:16px 0;page-break-inside:avoid} '
 + '.feature .ph{height:190px;background-size:cover;background-position:center;background-color:#0A1A2F} '
 + '.feature .fb{padding:14px 18px} '
 + '.feature h3{font-family:Georgia,serif;font-size:19px;color:#0A1A2F;margin:0 0 7px;line-height:1.3} '
 + '.feature p{margin:0 0 9px;font-size:14px;line-height:1.62;color:#2b3340} '
 + '.feature a{color:#2E9BE6;text-decoration:none;font-size:12.5px;font-weight:700} '
 + '.co{border:1px solid #E2E6EC;border-radius:8px;margin:14px 0;page-break-inside:avoid;overflow:hidden} '
 + '.co .hd{background:#0A1A2F;color:#fff;padding:9px 14px;font-family:Georgia,serif;font-size:16px;font-weight:700} '
 + '.co .hd img{height:20px;vertical-align:middle;margin-right:8px} '
 + '.co .bd{padding:8px 16px} '
 + '.co .row{margin:7px 0;font-size:13.5px;line-height:1.5} '
 + '.co .row .lab{display:inline-block;min-width:128px;padding-right:10px;color:#0A1A2F;font-weight:700;vertical-align:top} '
 + 'table.mv{width:100%;border-collapse:collapse;font-size:13px;margin:8px 0} '
 + 'table.mv th{background:#0A1A2F;color:#fff;text-align:left;padding:8px;font-size:11.5px} '
 + 'table.mv td{padding:8px;border-bottom:1px solid #E2E6EC;vertical-align:top} '
 + 'table.mv tr:nth-child(even) td{background:#F4F6F9} '
 + '.bonus p{font-size:14px;line-height:1.72;margin:0 0 10px} ';

function secH(kick,title){ return '<h2 class="sec"><span class="kick">'+esc(kick)+'</span>'+esc(title)+'</h2>'; }
function lead(t){ t=(t||'').toString(); if(!t) return ''; return '<p class="lead"><span class="dc">'+esc(t.charAt(0))+'</span>'+esc(t.slice(1))+'</p>'; }
function feature(s){ var im=(s.image||'').toString(); var ph=(/^https?:\/\//.test(im)||im.indexOf('data:')===0)?'<div class="ph" style="background-image:url('+im+')"></div>':''; var src=(s.source||'').toString(); var link=/^https?:\/\//.test(src)?'<a href="'+src+'">Read the source &rsaquo;</a>':(src?'<span style="color:#5A6472;font-size:12.5px">Source: '+esc(src)+'</span>':''); return '<div class="feature">'+ph+'<div class="fb"><h3>'+esc(s.headline)+'</h3><p>'+esc(s.story)+'</p>'+link+'</div></div>'; }
function coCard(r){ function row(lab,val,color){ if(val==null||val==='')val='Not specified'; var v=color?('<span style="color:'+color+';font-weight:700">'+esc(val)+'</span>'):esc(val); return '<div class="row"><span class="lab">'+lab+'</span>'+v+'</div>'; } return '<div class="co"><div class="hd">'+esc(r.company)+'</div><div class="bd">'+row('Key Development',r.development)+row('Strategic Theme',r.theme)+row('What It Signals',r.signals)+row('Market Impact / Risk',r.risk,riskColor(r.risk))+row('Watch Point',r.watch)+'</div></div>'; }
function movers(rows){ if(!rows||!rows.length) return '<p style="color:#5A6472">No notable leadership changes this period.</p>'; var h='<tr>'+['Company','Individual','Previous role','New role','Effective','Why it matters'].map(function(x){return '<th>'+x+'</th>';}).join('')+'</tr>'; var b=rows.map(function(r){return '<tr><td><b>'+esc(r.company)+'</b></td><td>'+esc(r.individual)+'</td><td>'+esc(r.previous)+'</td><td>'+esc(r.current)+'</td><td>'+esc(r.date)+'</td><td>'+esc(r.why)+'</td></tr>';}).join(''); return '<table class="mv">'+h+b+'</table>'; }

const coverHtml = cover ? ('<div class="cover"><div class="date">'+esc(dateStr)+'</div></div>') : '';
const bannerHtml = banner ? ('<img class="banner" src="'+banner+'"/>') : '<div class="issuebar" style="font-size:18px;font-family:Georgia,serif;text-transform:none">JARVIS INTELLIGENCE — Energy Brief</div>';
const heroHtml = hero ? '<div class="hero"></div>' : '';
const signoff = avatar ? ('<div style="text-align:center;padding:22px;border-top:3px solid #2E9BE6;margin-top:18px"><img src="'+avatar+'" style="width:96px;height:96px;border-radius:50%;border:2px solid #2E9BE6"/><div style="font-family:Georgia,serif;color:#0A1A2F;margin-top:8px;font-size:14px">Jarvis — AI News Reporter</div></div>') : '';

var body;
if (data) {
  var bonus=data.bonus||{}; var feats=data.featured||[]; var noc=data.noc||[]; var ioc=data.ioc||[];
  body = lead(data.intro)
    + (data.weekOverWeek ? ('<div class="callout"><b>What changed since last edition:</b> '+esc(data.weekOverWeek)+'</div>') : '')
    + (feats.length ? (secH('In focus','Featured Stories')+feats.map(feature).join('')) : '')
    + secH('Regional','Middle East NOCs') + noc.map(coCard).join('')
    + secH('Global','Supermajor IOCs') + ioc.map(coCard).join('')
    + secH('People','Movers & Shakers') + movers(data.movers)
    + secH('Analysis','Bonus Read'+(bonus.title?': '+esc(bonus.title):'')) + '<div class="bonus">'+(bonus.body?esc(bonus.body).split('\n').map(function(p){return '<p>'+p+'</p>';}).join(''):'')+'</div>';
} else {
  body = '<div class="callout" style="background:#FDECEC;border-color:#B02525">The analyst did not return structured data this run. Raw output below.</div><pre style="white-space:pre-wrap;font-family:inherit;font-size:12px">'+esc(raw)+'</pre>';
}

const html = '<!doctype html><html><head><meta charset="utf-8"><title>Energy Intelligence Brief — '+esc(weekOf)+'</title><style>'+CSS+'</style></head><body>'
  + coverHtml + bannerHtml
  + '<div class="issuebar">Weekly Energy Intelligence &nbsp;&middot;&nbsp; '+esc(weekOf)+'<span class="r">Confidential</span></div>'
  + heroHtml
  + '<div class="wrap">'+body+'</div>'
  + signoff + '</body></html>';
return [{ json: { date: date, html: html, markdown: raw } }];

const fs = require('fs');
const date = $json.date;
const html = $json.html;
const md = $json.markdown || '';
const dirs = ['/reports/energy-intelligence', '/reports/archive/energy-intelligence'];
for (var k = 0; k < dirs.length; k++) {
  try { fs.mkdirSync(dirs[k], { recursive: true }); fs.writeFileSync(dirs[k] + '/energy-intelligence-' + date + '.html', html); } catch (e) {}
}
try { fs.writeFileSync('/reports/archive/energy-intelligence/energy-intelligence-' + date + '.json', md); } catch (e) {}
try { fs.writeFileSync('/logs/last-run-success.txt', new Date().toISOString() + ' energy-intelligence'); } catch (e) {}
return [{ json: $json }];

